import heapq

class KthLargest:
    def __init__(self, k, nums):
        self.k = k
        self.heap = nums[:k]
        heapq.heapify(self.heap)
        for num in nums[k:]:
            if num > self.heap[0]:
                heapq.heapreplace(self.heap, num)

    def add(self, val):
        if len(self.heap) < self.k:
            heapq.heappush(self.heap, val)
        elif val > self.heap[0]:
            heapq.heapreplace(self.heap, val)
        return self.heap[0]

