    n := len(matrix)
    h := &CellHeap{{matrix[0][0], 0, 0}}
    heap.Init(h)
    visited := map[[2]int]bool{{0, 0}: true}
    val := 0
    for i := 0; i < k; i++ {
        c := heap.Pop(h).(Cell)
        val = c.val
        dirs := [][2]int{{c.r + 1, c.c}, {c.r, c.c + 1}}
        for _, d := range dirs {
            if d[0] < n && d[1] < n && !visited[d] {
                heap.Push(h, Cell{matrix[d[0]][d[1]], d[0], d[1]})
                visited[d] = true
            }
        }
    }
    return val
