        val = v;
        let dirs = [(r + 1, c), (r, c + 1)];
        for (nr, nc) in dirs {
            if nr < n && nc < n && !visited.contains(&(nr, nc)) {
                min_heap.push(Reverse((matrix[nr][nc], nr, nc)));
                visited.insert((nr, nc));
            }
        }
    }
    val
